let fieldLocks = { observer: false, species: false, locality: false };
function loadFieldLocks() {
  try { fieldLocks = { ...fieldLocks, ...(JSON.parse(localStorage.getItem(FIELD_LOCKS_KEY) || '{}') || {}) }; } catch {}
  renderFieldLocks();
}
function saveFieldLocks() { localStorage.setItem(FIELD_LOCKS_KEY, JSON.stringify(fieldLocks)); }
function renderFieldLocks() {
  document.querySelectorAll('[data-lock-field]').forEach(btn => {
    const field = btn.dataset.lockField;
    const locked = !!fieldLocks[field];
    btn.classList.toggle('locked', locked);
    btn.textContent = locked ? '🔒' : '🔓';
    const labels = { observer: 'Наблюдател', species: 'Вид', locality: 'Локация' };
    btn.title = locked ? `${labels[field] || field} е заключено за следващ запис` : `Заключи ${labels[field] || field} за следващ запис`;
    btn.setAttribute('aria-pressed', locked ? 'true' : 'false');
  });
}
function toggleFieldLock(field) {
  fieldLocks[field] = !fieldLocks[field];
  saveFieldLocks();
  renderFieldLocks();
  const labels = { observer: 'Наблюдател', species: 'Вид', locality: 'Локация' };
  setStatus(fieldLocks[field] ? `${labels[field] || field} ще се запази при следващ нов запис.` : `${labels[field] || field} вече няма да се пренася автоматично.`);
}
function lockedFieldValues() {
  const values = {};
  if (fieldLocks.observer && form.elements.observer) values.observer = form.elements.observer.value || '';
  if (fieldLocks.species && form.elements.species) values.species = form.elements.species.value || '';
  if (fieldLocks.locality && form.elements.locality) values.locality = form.elements.locality.value || '';
  return values;
}
