function derive(r) {
  const total = transectTotal(r);
  const open = n(r.bareSoil) + n(r.gravelSmallStones) + n(r.largeStones) + n(r.exposedRock);
  const stony = n(r.gravelSmallStones) + n(r.largeStones) + n(r.exposedRock);
  const shrubs = n(r.juniper) + n(r.otherShrubs);
  const visibility = ['visibilityN', 'visibilityNE', 'visibilityE', 'visibilitySE', 'visibilityS', 'visibilitySW', 'visibilityW', 'visibilityNW'].map(k => r[k]).filter(v => String(v).trim() !== '');
  const meanVisibility = visibility.length ? avg(visibility) : '';
  const cp = normaliseCoverPoints(r.coverPoints, total);
  const armParts = {};
  buildArmsFromConfig(r).forEach(a => { armParts['transect' + a.key] = cp.slice(a.start, a.end).join(';'); });
  return {
    meanSlope: avg([r.slope1, r.slope2, r.slope3]),
    aspectClass: r.aspectClass || aspectClass(r.aspectDeg),
    enteredCoverPoints: cp.filter(Boolean).length,
    herbaceousPct: pct(r.herbaceous, total),
    openSubstratePct: pct(open, total),
    stonySubstratePct: pct(stony, total),
    juniperPct: pct(r.juniper, total),
    shrubCoverPct: pct(shrubs, total),
    meanVisibility,
    visualObstruction: meanVisibility === '' ? '' : (100 - Number(meanVisibility)).toFixed(1),
    ...armParts
  };
}

function getFormData() {
  const fd = new FormData(form);
  const obj = { ...defaults };
  for (const [k, v] of fd.entries()) obj[k] = v;
  obj.id = document.getElementById('id').value || currentId || newId();
  obj.totalPoints = String(transectTotal(obj));
  obj.detectionBasis = Array.from(detectionSet);
  obj.coverPoints = normaliseCoverPoints(coverPoints, transectTotal(obj));
  obj.trackPoints = normaliseTrackPoints(trackPoints);
  obj.updatedAt = new Date().toISOString();
  obj.derived = derive(obj);
  return obj;
}

function setFormData(obj) {
  const r = { ...defaults, ...obj };
  currentId = r.id;
  detectionSet.clear();
  (r.detectionBasis || []).forEach(x => detectionSet.add(x));
  trackPoints = normaliseTrackPoints(r.trackPoints);
  for (const [k, v] of Object.entries(r)) {
    if (form.elements[k] && k !== 'coverPoints') form.elements[k].value = v ?? '';
  }
  document.getElementById('id').value = r.id;
  refreshTransectStructure(false, r);
  coverPoints = normaliseCoverPoints(r.coverPoints, transectTotal(r));
  activeArm = arms[0]?.key || 'N';
  selectedCoverIndex = firstEmptyIndexInArm(armByKey(activeArm));
  if (selectedCoverIndex === -1) selectedCoverIndex = armByKey(activeArm).start;
  syncCountsFromCoverPoints();
  renderAllCoverUI();
  resetSpeciesToggles();
  setSpeciesLockFromValue(r.species);
  updateSummaries();
  renderStationaryCompass();
  renderThreatOptions();
  renderFieldLocks();
}

function metric(value, text) { return `<div class="metric"><b>${xmlEscape(value)}</b><span>${xmlEscape(text)}</span></div>`; }
function updateSummaries() {
  const r = getFormData();
  const d = r.derived;
  const coverSummary = document.getElementById('coverSummary');
  if (coverSummary) coverSummary.innerHTML = metric(`${d.meanSlope || '—'}°`, 'среден наклон') + metric(`${d.herbaceousPct}%`, 'тревиста растителност') + metric(`${d.openSubstratePct}%`, 'открит субстрат') + metric(`${d.stonySubstratePct}%`, 'каменисто') + metric(`${d.juniperPct}%`, 'хвойна') + metric(`${d.shrubCoverPct}%`, 'храсти') + metric(`${d.enteredCoverPoints}/${transectTotal(r)}`, 'въведени точки');
  const visibilitySummary = document.getElementById('visibilitySummary');
  if (visibilitySummary) visibilitySummary.innerHTML = metric(`${d.meanVisibility || '—'}%`, 'средна видимост') + metric(`${d.visualObstruction || '—'}%`, 'закритост') + metric(`${r.juniperClumps || '—'}`, 'групи') + metric(`${r.grazingIndex || '—'}`, 'паша');
  renderCoverProgressOnly();
}

