function loadLocationHistory() {
  try { locationHistory = JSON.parse(localStorage.getItem(LOCATION_HISTORY_KEY) || '[]'); } catch { locationHistory = []; }
  const fromRecords = records.map(r => normaliseLocationText(r.locality)).filter(Boolean);
  locationHistory = Array.from(new Set([...locationHistory.map(normaliseLocationText).filter(Boolean), ...fromRecords]))
    .sort((a, b) => a.localeCompare(b, 'bg'));
  saveLocationHistory();
}
