function hideSpeciesSuggestions() {
  const box = document.getElementById('speciesSuggestions');
  if (box) box.classList.add('hidden');
}
function renderSpeciesSuggestions() {
  const input = form.elements.species;
  const box = document.getElementById('speciesSuggestions');
  if (!input || !box) return;
  if (input.readOnly) { box.classList.add('hidden'); box.innerHTML = ''; return; }
  const raw = normaliseLocationText(input.value);
  const q = raw.toLocaleLowerCase('bg');
  if (q.length < 3) { box.classList.add('hidden'); box.innerHTML = ''; return; }

  const official = BIRD_SPECIES
    .filter(s => String(s.bg || '').toLocaleLowerCase('bg').startsWith(q) || String(s.sci || '').toLowerCase().startsWith(q) || String(s.value || '').toLocaleLowerCase('bg').startsWith(q))
    .slice(0, 24);
  const history = speciesHistory
    .filter(val => !isOfficialSpeciesValue(val))
    .filter(val => val.toLocaleLowerCase('bg').startsWith(q) && val.toLocaleLowerCase('bg') !== q)
    .slice(0, Math.max(0, 24 - official.length));

  if (!official.length && !history.length) { box.classList.add('hidden'); box.innerHTML = ''; return; }
  const officialHtml = official.map(s => `<button type="button" class="location-suggestion" data-species="${xmlEscape(s.value)}">${speciesHtml(s)}</button>`).join('');
  const historyHtml = history.map(val => `<button type="button" class="location-suggestion" data-species="${xmlEscape(val)}"><span class="location-suggestion-name">${xmlEscape(val)}</span><span class="location-suggestion-remove" data-remove-species="${xmlEscape(val)}" title="Премахни от предложенията">×</span></button>`).join('');
  box.innerHTML = officialHtml + historyHtml;
  box.classList.remove('hidden');
  box.querySelectorAll('[data-species]').forEach(btn => {
    btn.onclick = (e) => {
      if (e.target && e.target.dataset && e.target.dataset.removeSpecies) return;
      const val = btn.dataset.species || '';
      input.value = val;
      setSpeciesLockFromValue(val);
      hideSpeciesSuggestions();
      updateSummaries();
      scheduleAutosave();
      setStatus(`Избран е вид: ${val}`);
    };
  });
  box.querySelectorAll('[data-remove-species]').forEach(btn => {
    btn.onclick = (e) => {
      e.preventDefault(); e.stopPropagation();
      removeSpeciesFromHistory(btn.dataset.removeSpecies || '');
    };
  });
}
