  if (!Number.isFinite(lat) || !Number.isFinite(lon)) return;
  const p = {
    lat, lon,
    elevation: data.altitude != null && Number.isFinite(Number(data.altitude)) ? Number(data.altitude) : '',
    accuracy: data.accuracy != null && Number.isFinite(Number(data.accuracy)) ? Number(data.accuracy) : '',
    verticalAccuracy: data.verticalAccuracy != null && Number.isFinite(Number(data.verticalAccuracy)) ? Number(data.verticalAccuracy) : '',
    time: data.time ? new Date(Number(data.time)).toISOString() : new Date().toISOString()
  };
