function applyLocation(lat, lon, alt, acc, vAcc, provider, altitudeSource) {
  if (lat == null || lon == null || !Number.isFinite(Number(lat)) || !Number.isFinite(Number(lon))) {
    setStatus('Получена е невалидна GPS позиция. Пробвай отново на открито.');
    return;
  }
  form.elements.latitude.value = Number(lat).toFixed(6);
  form.elements.longitude.value = Number(lon).toFixed(6);
  if (acc != null && Number.isFinite(Number(acc))) form.elements.gpsAccuracy.value = Number(acc).toFixed(1);
  if (vAcc != null && Number.isFinite(Number(vAcc)) && form.elements.verticalAccuracy) form.elements.verticalAccuracy.value = Number(vAcc).toFixed(1);
  if (alt != null && Number.isFinite(Number(alt))) {
    form.elements.elevation.value = Number(alt).toFixed(1);
    if (form.elements.altitudeSource) form.elements.altitudeSource.value = altitudeSource || provider || 'gps';
  }
  myLocation = { lat: Number(lat), lon: Number(lon), accuracy: acc ?? '', time: new Date().toISOString() };
  updateSummaries();
  const h = acc ? `хор. точност ${Number(acc).toFixed(1)} m` : 'без хор. точност';
  const v = vAcc ? `верт. точност ${Number(vAcc).toFixed(1)} m` : 'без верт. точност';
  const altMsg = (alt != null && Number.isFinite(Number(alt))) ? `; височина ${Number(alt).toFixed(1)} m (${v})` : '; височината още не е надеждно подадена от GPS';
  scheduleAutosave();
  setStatus(`GPS координатите са добавени в „Основни“: ${h}${altMsg}. За финални анализи височината може да се провери/замени с DEM в QGIS.`);
}

function setMyLocationFromData(data) {
  const lat = Number(data?.latitude), lon = Number(data?.longitude);
  if (!Number.isFinite(lat) || !Number.isFinite(lon)) return false;
  myLocation = {
    lat, lon,
    accuracy: data.accuracy != null && Number.isFinite(Number(data.accuracy)) ? Number(data.accuracy) : '',
    time: data.time ? new Date(Number(data.time)).toISOString() : new Date().toISOString()
  };
  const hasAnyPoint = records.some(validCoord) || hasUsableCoordValues(form.elements.latitude.value, form.elements.longitude.value) || trackPoints.length >= 2;
  renderMap({ includeRecords: true, includeFormPoint: true, includeTrack: true, centerMyLocation: !hasAnyPoint, fitToContent: false });
  return true;
}

function receiveLocationData(data) {
  if (data && data.error) { setStatus(data.error); pendingLocationMode = null; return; }
  const mode = pendingLocationMode || 'mapPosition';
  pendingLocationMode = null;

  if (mode === 'form') {
    applyLocation(data.latitude, data.longitude, data.altitude, data.accuracy, data.verticalAccuracy, data.provider, data.altitudeSource);
    renderMap();
    return;
  }

  if (mode === 'track') {
    setMyLocationFromData(data);
    addTrackPointFromData(data);
    setStatus(`GPS трак: добавена/проверена е точка. Общо точки: ${trackPoints.length}.`);
    return;
  }

  setMyLocationFromData(data);
  const acc = data?.accuracy != null && Number.isFinite(Number(data.accuracy)) ? ` Точност: ${Number(data.accuracy).toFixed(1)} m.` : '';
  setStatus(`Моето местоположение е показано на картата.${acc} Координатите в „Основни“ не са променени.`);
}

window.receiveNativeLocation = function(payload) {
  try {
    const data = typeof payload === 'string' ? JSON.parse(payload) : payload;
    receiveLocationData(data);
  } catch { pendingLocationMode = null; setStatus('Неуспешно прочитане на GPS позиция от Android приложението.'); }
};

function requestMapPosition(showMessage = true) {
  pendingLocationMode = 'mapPosition';
  if (showMessage) setStatus('Изчакване на текущото местоположение за показване върху картата. Това не променя координатите в „Основни“.');
  if (window.AndroidBridge && typeof window.AndroidBridge.requestLocation === 'function') {
    window.AndroidBridge.requestLocation();
    return;
  }
  if (navigator.geolocation) {
    navigator.geolocation.getCurrentPosition(pos => {
      receiveLocationData({
        latitude: pos.coords.latitude,
        longitude: pos.coords.longitude,
        altitude: pos.coords.altitude,
        accuracy: pos.coords.accuracy,
        verticalAccuracy: pos.coords.altitudeAccuracy,
        provider: 'browser_map',
        altitudeSource: 'browser_gps',
        time: Date.now()
      });
    }, () => { pendingLocationMode = null; setStatus('Неуспешно показване на текущото местоположение върху картата.'); }, { enableHighAccuracy: true, timeout: 30000, maximumAge: 0 });
  } else {
    pendingLocationMode = null;
    setStatus('Устройството не поддържа GPS за показване върху картата.');
  }
}

function useGPS() {
  pendingLocationMode = 'form';
  if (window.AndroidBridge && typeof window.AndroidBridge.requestLocation === 'function') {
    setStatus('Изчакване на GPS координати за полетата в „Основни“. За по-добра надморска височина остани на открито до 60 секунди...');
    window.AndroidBridge.requestLocation();
    return;
  }
  if (!window.isSecureContext) { pendingLocationMode = null; setStatus('GPS изисква HTTPS, инсталирана PWA или Android APK версия. Отвори GitHub Pages адреса, не локален файл.'); return; }
  if (!navigator.geolocation) { pendingLocationMode = null; setStatus('Браузърът не поддържа GPS.'); return; }
  setStatus('Изчакване на GPS позиция с висока точност за полетата в „Основни“...');
  navigator.geolocation.getCurrentPosition(pos => {
    receiveLocationData({
      latitude: pos.coords.latitude,
      longitude: pos.coords.longitude,
      altitude: pos.coords.altitude,
      accuracy: pos.coords.accuracy,
      verticalAccuracy: pos.coords.altitudeAccuracy,
      provider: 'browser',
      altitudeSource: 'browser_gps',
      time: Date.now()
    });
  }, err => {
    pendingLocationMode = null;
    const msg = err.code === 1 ? 'Достъпът до локация е отказан. Разреши Location за Chrome/приложението.' : err.code === 2 ? 'Позицията не може да бъде определена. Излез на открито и пробвай пак.' : 'Времето за GPS изтече. Пробвай отново на открито.';
    setStatus(msg);
  }, { enableHighAccuracy: true, timeout: 60000, maximumAge: 0 });
}

function syncCountsFromCoverPoints() {
  const total = transectTotal();
  coverPoints = normaliseCoverPoints(coverPoints, total);
  const counts = Object.fromEntries(coverCategories.map(c => [c.key, 0]));
  coverPoints.forEach(k => { if (k && counts[k] !== undefined) counts[k] += 1; });
  coverCategories.forEach(c => { if (form.elements[c.key]) form.elements[c.key].value = counts[c.key] || ''; });
  form.elements.totalPoints.value = String(total);
}
function addCoverPoint(cat) {
  const arm = armByKey(activeArm);
  ensureSelectedPointInActiveArm();
  let idx = selectedCoverIndex;
  if (idx == null || idx < arm.start || idx >= arm.end) idx = firstEmptyIndexInArm(arm);
  if (idx === -1 || idx == null) { setStatus(`Лъч ${arm.key} е попълнен. Избери друг лъч или точка за корекция.`); return; }
  coverPoints[idx] = cat;
  const pointNumber = idx - arm.start + 1;
  const next = firstEmptyIndexInArm(arm);
  selectedCoverIndex = next === -1 ? idx : next;
  syncCountsFromCoverPoints();
  renderAllCoverUI();
  updateSummaries();
  scheduleAutosave();
  setStatus(`Въведена е точка ${arm.key}${pointNumber}: ${coverByKey[cat].label}.`);
}
function undoCoverPoint() {
  const arm = armByKey(activeArm);
  for (let i = arm.end - 1; i >= arm.start; i--) {
    if (coverPoints[i]) { coverPoints[i] = ''; selectedCoverIndex = i; syncCountsFromCoverPoints(); renderAllCoverUI(); updateSummaries(); scheduleAutosave(); setStatus(`Премахната е последната точка от лъч ${arm.key}.`); return; }
  }
  for (let i = coverPoints.length - 1; i >= 0; i--) {
    if (coverPoints[i]) { coverPoints[i] = ''; selectedCoverIndex = i; activeArm = (arms.find(a => i >= a.start && i < a.end) || armByKey(activeArm)).key; syncCountsFromCoverPoints(); renderAllCoverUI(); updateSummaries(); scheduleAutosave(); setStatus('Премахната е последната въведена точка.'); return; }
  }
}
function clearCoverPoints() {
  if (!filledPoints() || confirm('Да изчистя ли всички въведени точки за покривка?')) {
    refreshTransectStructure(false);
    coverPoints = normaliseCoverPoints([], transectTotal()); activeArm = arms[0]?.key || 'N'; selectedCoverIndex = 0; syncCountsFromCoverPoints(); renderAllCoverUI(); updateSummaries(); autosaveCurrentRecord(); setStatus('Точките за покривка са изчистени.');
  }
}
function renderCoverProgressOnly() {
  const done = filledPoints();
  const total = transectTotal();
  const pctDone = total ? Math.min(100, (done / total) * 100) : 0;
  const t = document.getElementById('coverProgressText');
  const b = document.getElementById('coverProgressBar');
  const a = document.getElementById('activeTransectText');
  if (t) t.textContent = `${done} / ${total}`;
  if (b) b.style.width = pctDone + '%';
  if (a) { const arm = armByKey(activeArm); a.textContent = `Активен лъч: ${activeArm} (${armProgress(arm)}/${arm.end - arm.start})`; }
  const sp = document.getElementById('selectedPointText');
  if (sp) sp.textContent = `Избрана точка: ${selectedPointLabel()}`;
  renderTransectScheme();
}
function renderTransectButtons() {
  const box = document.getElementById('transectButtons');
  if (!box) return;
  box.innerHTML = arms.map(a => `<button type="button" class="transect-btn ${a.key === activeArm ? 'active' : ''}" data-arm="${a.key}">${a.key}<br><span class="meta">${armProgress(a)}/${a.end - a.start}</span></button>`).join('');
  box.querySelectorAll('[data-arm]').forEach(btn => btn.onclick = () => setActiveArm(btn.dataset.arm));
}
function renderCoverPointGrid() {
  const grid = document.getElementById('coverPointGrid');
  if (!grid) return;
  ensureSelectedPointInActiveArm();
  const a = armByKey(activeArm);
  const cells = coverPoints.slice(a.start, a.end).map((key, j) => {
    const idx = a.start + j;
    const cat = coverByKey[key];
    const pointNo = j + 1;
    const selected = idx === selectedCoverIndex ? ' selected' : '';
    const content = cat ? `<span class="ptno">${pointNo}</span><span class="ptcat">${cat.short}</span>` : `<span class="ptno">${pointNo}</span><span class="ptcat">—</span>`;
    return `<div class="pointcell ${cat ? cat.cls : 'empty'}${selected}" data-index="${idx}" title="${a.key}${pointNo}: ${cat ? cat.label : 'празно'}">${content}</div>`;
  }).join('');
  grid.innerHTML = `<div class="transect-card"><div class="transect-title"><span>${a.label}</span><span>${armProgress(a)}/${a.end - a.start}</span></div><div class="transect-cells">${cells}</div></div>`;
  grid.querySelectorAll('[data-index]').forEach(cell => cell.onclick = () => selectCoverPoint(Number(cell.dataset.index)));
}
function renderCoverCategories() {
  const box = document.getElementById('coverCategoryButtons');
  if (box) {
    box.innerHTML = coverCategories.map(c => `<button type="button" class="catbtn" data-covercat="${c.key}"><span class="cover-dot ${c.cls}" aria-hidden="true"></span><span><b>${c.short}</b> — ${c.label}</span></button>`).join('');
    box.querySelectorAll('[data-covercat]').forEach(btn => btn.onclick = () => addCoverPoint(btn.dataset.covercat));
  }
}
function renderCoverStats() {
  const box = document.getElementById('coverStatsTable');
  const status = document.getElementById('coverStatsStatus');
  if (!box) return;
  const total = transectTotal();
  const counts = Object.fromEntries(coverCategories.map(c => [c.key, 0]));
  normaliseCoverPoints(coverPoints, total).forEach(k => { if (k && counts[k] !== undefined) counts[k] += 1; });
  const done = Object.values(counts).reduce((s, x) => s + x, 0);
  const rows = coverCategories.map(c => `<tr><td><span class="legend-dot ${c.cls}"></span> <b>${c.short}</b> — ${c.label}</td><td>${counts[c.key]}</td><td>${pct(counts[c.key], total)}%</td></tr>`).join('');
  const open = counts.bareSoil + counts.gravelSmallStones + counts.largeStones + counts.exposedRock;
  const stony = counts.gravelSmallStones + counts.largeStones + counts.exposedRock;
  const shrubs = counts.juniper + counts.otherShrubs;
  box.innerHTML = `<table class="stats-table"><thead><tr><th>Категория</th><th>Брой</th><th>% от ${total}</th></tr></thead><tbody>${rows}<tr><th>Открит субстрат: гола почва + камъни + скала</th><th>${open}</th><th>${pct(open, total)}%</th></tr><tr><th>Каменист субстрат: чакъл + едри камъни + скала</th><th>${stony}</th><th>${pct(stony, total)}%</th></tr><tr><th>Храстово покритие: хвойна + други храсти</th><th>${shrubs}</th><th>${pct(shrubs, total)}%</th></tr></tbody></table>`;
  if (status) status.innerHTML = done === total ? `<span class="oktext">Попълнени са всички ${total} точки. Процентите са готови за използване в анализа.</span>` : `<span class="warn">Попълнени са ${done}/${total} точки. Процентите са временни и ще станат окончателни след попълване на всички точки.</span>`;
}
function renderAllCoverUI() { renderTransectButtons(); renderCoverPointGrid(); renderCoverProgressOnly(); renderCoverStats(); }


function oppositeDirection(dir) {
  return { N:'S', NE:'SW', E:'W', SE:'NW', S:'N', SW:'NE', W:'E', NW:'SE' }[dir] || '';
}

let deviceCompassStarted = false;
let compassRawHeading = null;
let compassDisplayHeading = null;
let compassLastPaint = 0;
let compassRaf = null;
function normalizeCompassHeading(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return null;
  return ((n % 360) + 360) % 360;
}
function shortestCompassDelta(from, to) {
  let delta = normalizeCompassHeading(to) - normalizeCompassHeading(from);
  if (delta > 180) delta -= 360;
  if (delta < -180) delta += 360;
  return delta;
}
function smoothCompassHeading(nextHeading) {
  const h = normalizeCompassHeading(nextHeading);
  if (h === null) return null;
  if (compassDisplayHeading === null) {
    compassDisplayHeading = h;
    return h;
  }
  const delta = shortestCompassDelta(compassDisplayHeading, h);

  // Deadband against small magnetic/noise movements. This removes the visible trembling.
  if (Math.abs(delta) < 2.8) return compassDisplayHeading;

  // Slow smoothing for normal noise; faster response when the phone is clearly turned.
  const alpha = Math.abs(delta) > 55 ? 0.28 : 0.11;
  compassDisplayHeading = normalizeCompassHeading(compassDisplayHeading + delta * alpha);
  return compassDisplayHeading;
}
function paintDeviceCompassArrow() {
  compassRaf = null;
  const arrow = document.getElementById('deviceCompassArrow');
  if (!arrow) return;
  const h = smoothCompassHeading(compassRawHeading);
  if (h === null) {
    arrow.classList.add('unavailable');
    return;
  }
  arrow.classList.remove('unavailable');
  arrow.style.transform = `translate(-50%, -50%) rotate(${-h}deg)`;
  arrow.title = `Компас: ${Math.round(h)}°`;
}
function updateDeviceCompassArrow(heading) {
  const h = normalizeCompassHeading(heading);
  const arrow = document.getElementById('deviceCompassArrow');
  if (!arrow) return;
  if (h === null) {
    arrow.classList.add('unavailable');
    return;
  }
  compassRawHeading = h;
  const now = Date.now();

  // Limit repaint frequency. Sensor events can arrive very often and cause flicker.
  if (now - compassLastPaint < 140) return;
  compassLastPaint = now;
  if (!compassRaf) compassRaf = requestAnimationFrame(paintDeviceCompassArrow);
}

window.receiveNativeCompass = function(payload) {
  try {
    const obj = typeof payload === 'string' ? JSON.parse(payload) : payload;
    if (!obj || obj.error) {
      updateDeviceCompassArrow(null);
      return;
    }
    updateDeviceCompassArrow(obj.heading);
  } catch (e) {
    updateDeviceCompassArrow(null);
  }
};

function startDeviceCompassArrow() {
  if (deviceCompassStarted) return;
  const arrow = document.getElementById('deviceCompassArrow');
  if (!arrow) return;
  deviceCompassStarted = true;
  arrow.classList.add('unavailable');

  // Android APK: use native SensorManager compass when available. It is more stable
  // than raw WebView DeviceOrientation events on many phones.
  try {
    if (window.AndroidBridge && typeof window.AndroidBridge.startCompass === 'function') {
      window.AndroidBridge.startCompass();
      return;
    }
  } catch (e) {}

  const handler = (event) => {
    let heading = null;
    if (typeof event.webkitCompassHeading === 'number') {
      heading = event.webkitCompassHeading;
    } else if (typeof event.alpha === 'number') {
      // Android WebView usually reports alpha as the rotation around the Z axis.
      heading = 360 - event.alpha;
    }
    updateDeviceCompassArrow(heading);
  };
  const attach = () => {
    // Prefer absolute orientation when available; keep the ordinary event as fallback.
    window.addEventListener('deviceorientationabsolute', handler, true);
    window.addEventListener('deviceorientation', handler, true);
  };
  try {
    if (window.DeviceOrientationEvent && typeof window.DeviceOrientationEvent.requestPermission === 'function') {
      window.DeviceOrientationEvent.requestPermission().then((state) => {
        if (state === 'granted') attach();
        else updateDeviceCompassArrow(null);
      }).catch(() => updateDeviceCompassArrow(null));
    } else {
      attach();
    }
  } catch (e) {
    updateDeviceCompassArrow(null);
  }
}

function setStationaryDirection(dir) {
  if (form.elements.flightFrom) form.elements.flightFrom.value = dir;
  if (form.elements.flightTo) form.elements.flightTo.value = oppositeDirection(dir);
  renderStationaryCompass();
  scheduleAutosave();
}
function renderStationaryCompass() {
  const box = document.getElementById('stationaryCompass');
  if (!box) return;
  const from = form.elements.flightFrom ? form.elements.flightFrom.value : '';
  box.querySelectorAll('[data-dir]').forEach(btn => btn.classList.toggle('active', btn.dataset.dir === from));
  const night = form.elements.migrationType && form.elements.migrationType.value === 'night';
  const nightBox = document.getElementById('nightMigrationFields');
  const dayBox = document.getElementById('dayMigrationFields');
  if (nightBox) nightBox.classList.toggle('hidden', !night);
  if (dayBox) dayBox.classList.toggle('hidden', false);
}

